# PowerShell script to setup local nezlephant stub and build envapt-nezlephant
# Run this from the repository root (where envapt/ and envapt-nezlephant/ live)

$root = Split-Path -Parent $MyInvocation.MyCommand.Path
Write-Host "Root: $root"

# Ensure stub exists
$stubDir = Join-Path $root 'nezlephant'
if (-not (Test-Path $stubDir)) {
  Write-Host "Stub folder not found at $stubDir. Creating minimal stub..."
  New-Item -ItemType Directory -Path $stubDir | Out-Null
  New-Item -ItemType Directory -Path (Join-Path $stubDir 'src') | Out-Null
  Set-Content -Path (Join-Path $stubDir 'package.json') -Value '{"name":"@funeste38/nezlephant","version":"0.0.0-stub","main":"src/index.js"}' -Encoding UTF8
  Set-Content -Path (Join-Path $stubDir 'src\index.js') -Value "exports.decodeNezlephantBuffer = function(buf){ try{return buf.toString('utf8')}catch(e){return ''}};" -Encoding UTF8
}

# Install dependencies for plugin and link local stub
$pluginDir = Join-Path $root 'envapt-nezlephant'
if (-not (Test-Path $pluginDir)) { Write-Error "Plugin dir not found: $pluginDir"; exit 1 }

Push-Location $pluginDir
Write-Host "In $pluginDir: installing local stub and dev deps..."
# Install local stub into plugin
npm install "..\nezlephant"
# Install dev deps (typescript + node types)
npm install --save-dev typescript @types/node

# Install runtime deps
npm install

# Build ESM output
Write-Host "Building ESM output..."
npx tsc -p tsconfig.json
# Build CommonJS output
Write-Host "Building CommonJS output..."
npx tsc -p tsconfig.json --module commonjs --outDir dist-cjs

Pop-Location

Write-Host "Done. Plugin built. You can now link or install the plugin into your app as needed."